# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit

// MARK: - Password Reset Deep Link Model

struct PasswordResetDeepLink {
    let token: String
    let email: String?
    let expiresAt: Date?
    
    init?(url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return nil
        }
        
        // Validate the host and path
        guard components.host == "myapp.com",
              components.path == "/reset-password" else {
            return nil
        }
        
        // Parse query parameters
        let queryItems = components.queryItems ?? []
        
        guard let token = queryItems.first(where: { $0.name == "token" })?.value,
              !token.isEmpty else {
            return nil
        }
        
        self.token = token
        self.email = queryItems.first(where: { $0.name == "email" })?.value
        
        if let expiresString = queryItems.first(where: { $0.name == "expires" })?.value,
           let expiresInterval = TimeInterval(expiresString) {
            self.expiresAt = Date(timeIntervalSince1970: expiresInterval)
        } else {
            self.expiresAt = nil
        }
    }
    
    var isExpired: Bool {
        guard let expiresAt = expiresAt else { return false }
        return Date() > expiresAt
    }
}

// MARK: - Universal Link Router

enum DeepLinkDestination {
    case passwordReset(PasswordResetDeepLink)
    case unknown
}

class UniversalLinkRouter {
    
    static let shared = UniversalLinkRouter()
    
    private init() {}
    
    func route(from url: URL) -> DeepLinkDestination {
        if let resetLink = PasswordResetDeepLink(url: url) {
            return .passwordReset(resetLink)
        }
        return .unknown
    }
}

// MARK: - Navigation Coordinator

protocol NavigationCoordinating: AnyObject {
    func navigateToPasswordReset(with deepLink: PasswordResetDeepLink)
    func showAlert(title: String, message: String)
}

class AppNavigationCoordinator: NavigationCoordinating {
    
    weak var window: UIWindow?
    
    init(window: UIWindow?) {
        self.window = window
    }
    
    func navigateToPasswordReset(with deepLink: PasswordResetDeepLink) {
        guard !deepLink.isExpired else {
            showAlert(title: "Link Expired", message: "This password reset link has expired. Please request a new one.")
            return
        }
        
        let resetVC = PasswordResetViewController()
        resetVC.configure(with: deepLink)
        
        // Navigate to reset screen
        if let navigationController = findTopNavigationController() {
            // Dismiss any presented view controllers first
            if let presented = navigationController.presentedViewController {
                presented.dismiss(animated: false) {
                    navigationController.pushViewController(resetVC, animated: true)
                }
            } else {
                navigationController.pushViewController(resetVC, animated: true)
            }
        } else if let rootVC = window?.rootViewController {
            let navController = UINavigationController(rootViewController: resetVC)
            navController.modalPresentationStyle = .fullScreen
            
            if let presented = rootVC.presentedViewController {
                presented.dismiss(animated: false) {
                    rootVC.present(navController, animated: true)
                }
            } else {
                rootVC.present(navController, animated: true)
            }
        }
    }
    
    func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        
        if let topVC = findTopViewController() {
            topVC.present(alert, animated: true)
        }
    }
    
    private func findTopNavigationController() -> UINavigationController? {
        guard let rootVC = window?.rootViewController else { return nil }
        
        if let navController = rootVC as? UINavigationController {
            return navController
        }
        
        if let tabController = rootVC as? UITabBarController,
           let navController = tabController.selectedViewController as? UINavigationController {
            return navController
        }
        
        return nil
    }
    
    private func findTopViewController() -> UIViewController? {
        guard var topVC = window?.rootViewController else { return nil }
        
        while let presented = topVC.presentedViewController {
            topVC = presented
        }
        
        if let navController = topVC as? UINavigationController {
            return navController.topViewController ?? navController
        }
        
        if let tabController = topVC as? UITabBarController {
            return tabController.selectedViewController ?? tabController
        }
        
        return topVC
    }
}

