// MARK: - Password Reset Service

enum PasswordResetError: LocalizedError {
    case invalidToken
    case tokenExpired
    case networkError
    case serverError(String)
    
    var errorDescription: String? {
        switch self {
        case .invalidToken:
            return "The reset token is invalid. Please request a new password reset link."
        case .tokenExpired:
            return "This reset link has expired. Please request a new password reset link."
        case .networkError:
            return "Unable to connect to the server. Please check your internet connection and try again."
        case .serverError(let message):
            return message
        }
    }
}

class PasswordResetService {
    
    static let shared = PasswordResetService()
    
    private let baseURL = "https://api.myapp.com"
    
    private init() {}
    
    func resetPassword(token: String, newPassword: String, completion: @escaping (Result<Void, PasswordResetError>) -> Void) {
        guard let url = URL(string: "\(baseURL)/auth/reset-password") else {
            completion(.failure(.networkError))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.timeoutInterval = 30
        
        let body: [String: String] = [
            "token": token,
            "new_password": newPassword
        ]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
        } catch {
            completion(.failure(.networkError))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let _ = error {
                completion(.failure(.networkError))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.networkError))
                return
            }
            
            switch httpResponse.statusCode {
            case 200...299:
                completion(.success(()))
            case 400:
                completion(.failure(.invalidToken))
            case 410:
                completion(.failure(.tokenExpired))
            default:
                if let data = data,
                   let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                   let message = json["message"] as? String {
                    completion(.failure(.serverError(message)))
                } else {
                    completion(.failure(.serverError("An unexpected error occurred. Please try again.")))
                }
            }
        }.resume()
    }
    
    func validateToken(_ token: String, completion: @escaping (Result<Bool, PasswordResetError>) -> Void) {
        guard let url = URL(string: "\(baseURL)/auth/validate-reset-token?token=\(token)") else {
            completion(.failure(.networkError))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.timeoutInterval = 15
        
        URLSession.shared.dataTask(with: request) { _, response, error in
            if let _ = error {
                completion(.failure(.networkError))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.networkError))
                return
            }
            
            switch httpResponse.statusCode {
            case 200:
                completion(.success(true))
            case 400:
                completion(.failure(.invalidToken))
            case 410:
                completion(.failure(.tokenExpired))
            default:
                completion(.failure(.networkError))
            }
        }.resume()
    }
}

// MARK: - SceneDelegate Universal Link Handling

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private lazy var navigationCoordinator = AppNavigationCoordinator(window: window)
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        window = UIWindow(windowScene: windowScene)
        
        // Set up your root view controller
        let rootViewController = UIViewController()
        rootViewController.view.backgroundColor = .systemBackground
        let navigationController = UINavigationController(rootViewController: rootViewController)
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
        
        // Handle universal links from cold launch
        if let urlContext = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContext.url)
        }
        
        if let userActivity = connectionOptions.userActivities.first {
            handleUserActivity(userActivity)
        }
    }
    
    // Handle universal links when app is already running
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        handleUserActivity(userActivity)
    }
    
    // Handle URL scheme links
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        handleIncomingURL(url)
    }
    
    private func handleUserActivity(_ userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleIncomingURL(url)
    }
    
    private func handleIncomingURL(_ url: URL) {
        let destination = UniversalLinkRouter.shared.route(from: url)
        
        switch destination {
        case .passwordReset(let deepLink):
            // Optionally validate token before navigating
            PasswordResetService.shared.validateToken(deepLink.token) { [weak self] result in
                DispatchQueue.main.async {
                    switch result {
                    case .success:
                        self?.navigationCoordinator.navigateToPasswordReset(with: deepLink)
                    case .failure(let error):
                        self?.navigationCoordinator.showAlert(
                            title: "Invalid Link",
                            message: error.localizedDescription
                        )
                    }
                }
            }
            
        case .unknown:
            print("Unhandled universal link: \(url)")
        }
    }
}

// MARK: - AppDelegate Universal Link Handling (for iOS 12 and earlier or non-scene based apps)

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    private lazy var navigationCoordinator = AppNavigationCoordinator(window: window)
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        return true
    }
    
    // MARK: UISceneSession Lifecycle
    
    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession, options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        return UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
    }
    
    // Handle universal links (non-scene based apps)
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        let destination = UniversalLinkRouter.shared.route(from: url)
        
        switch destination {
        case .passwordReset(let deepLink):
            navigationCoordinator.navigateToPasswordReset(with: deepLink)
            return true
        case .unknown:
            return false
        }
    }
    
    // Handle custom URL scheme (fallback)
    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey: Any] = [:]) -> Bool {
        let destination = UniversalLinkRouter.shared.route(from: url)
        
        switch destination {
        case .passwordReset(let deepLink):
            navigationCoordinator.navigateToPasswordReset(with: deepLink)
            return true
        case .unknown:
            return false
        }
    }
}